package com.corporativoalpha.catalogservice.models;import jakarta.persistence.*;import jakarta.validation.constraints.Min;import jakarta.validation.constraints.NotBlank;import jakarta.validation.constraints.NotNull;@Entity@Table(name = "spaces")public class Space {@Id@GeneratedValue(strategy = GenerationType.IDENTITY)private Long id;@NotBlank@Column(nullable = false)private String name;@NotBlank@Column(nullable = false)private String type;@NotNull@Min(1)@Column(nullable = false)private Integer capacity;private String resources;private String location;public Long getId(){return id;}public void setId(Long id){this.id=id;}public String getName(){return name;}public void setName(String name){this.name=name;}public String getType(){return type;}public void setType(String type){this.type=type;}public Integer getCapacity(){return capacity;}public void setCapacity(Integer capacity){this.capacity=capacity;}public String getResources(){return resources;}public void setResources(String resources){this.resources=resources;}public String getLocation(){return location;}public void setLocation(String location){this.location=location;}}
